// Marks the parent workflow run as FAILED on the backend and forwards the
// error message to the Slack alerting webhook (if configured).
//
// Inputs ($json):
//   - workflowRunId : long — the run to fail
//   - errorMessage  : string — short human-readable explanation
//   - errorPayload  : object — optional structured context (stack, http status, ...)
//
// Output:
//   - failed           : true
//   - completionStatus : 'FAILED'
//
// Reads:
//   - APP_VIDEO_OPS_BACKEND_BASE_URL
//   - APP_VIDEO_OPS_INTERNAL_API_SECRET    (legacy fallback)
//   - APP_VIDEO_OPS_WORKFLOW_CALLBACK_HMAC_SECRET
//   - APP_ALERTING_SLACK_WEBHOOK_URL       (optional)

const crypto = require('crypto');
const https = require('https');
const http = require('http');
const { URL } = require('url');

const backendBase = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
if (!backendBase) {
  throw new Error('APP_VIDEO_OPS_BACKEND_BASE_URL env var is empty.');
}
const hmacSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_HMAC_SECRET || '');
const legacySecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const slackUrl = String($env.APP_ALERTING_SLACK_WEBHOOK_URL || '');

const workflowRunId = Number($json.workflowRunId || 0);
if (!workflowRunId || workflowRunId <= 0) {
  throw new Error('workflowRunId is required and must be > 0.');
}
const errorMessage = String($json.errorMessage || 'Unknown workflow error');
const errorPayload = $json.errorPayload && typeof $json.errorPayload === 'object'
  ? $json.errorPayload : {};

const body = {
  status: 'FAILED',
  errorMessage,
  errorPayload,
};
const bodyJson = JSON.stringify(body);
const path = '/api/video-ops/workflow-runs/' + workflowRunId + '/complete';

const headers = { 'Content-Type': 'application/json' };
if (hmacSecret) {
  const timestamp = String(Math.floor(Date.now() / 1000));
  const payload = 'POST\n' + path + '\n' + timestamp + '\n' + bodyJson;
  headers['X-Workflow-Timestamp'] = timestamp;
  headers['X-Workflow-Signature'] = crypto.createHmac('sha256', hmacSecret).update(payload, 'utf8').digest('hex');
} else if (legacySecret) {
  headers['X-Workflow-Callback-Secret'] = legacySecret;
}

function post(urlString, payloadString, payloadHeaders) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlString);
    const lib = url.protocol === 'https:' ? https : http;
    const req = lib.request(
      {
        method: 'POST',
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        headers: { ...payloadHeaders, 'Content-Length': Buffer.byteLength(payloadString) },
      },
      (res) => {
        let chunks = '';
        res.on('data', (c) => { chunks += c; });
        res.on('end', () => resolve({ status: res.statusCode || 0, body: chunks }));
      }
    );
    req.on('error', reject);
    req.write(payloadString);
    req.end();
  });
}

const backendResp = await post(backendBase + path, bodyJson, headers);

if (slackUrl) {
  try {
    const slackPayload = JSON.stringify({
      text: ':rotating_light: n8n workflow run failed',
      blocks: [{
        type: 'section',
        text: { type: 'mrkdwn', text: '*Run ' + workflowRunId + '* failed:\n```' + errorMessage + '```' },
      }],
    });
    await post(slackUrl, slackPayload, { 'Content-Type': 'application/json' });
  } catch (e) { /* swallow alerting errors so we don't mask the real failure */ }
}

return [{
  json: {
    failed: true,
    completionStatus: 'FAILED',
    backendStatus: backendResp.status,
    backendBody: backendResp.body,
  },
}];
